+    #[test]
+    fn extract_comm_no_comm_field() {
+        let events = vec![ProcessEvent {
+            timestamp: Utc::now(),
+            event_type: EventType::ProcessExit,
+            details: Some(serde_json::json!({"pid": 42}).to_string()),
