+        let alternatives = vec![
+            AlternativePlan {
+                description: "safe".to_string(),
+                action_count: 1,
+                total_loss: 2.0,
+                goal_achievement: vec![],
+            },
+            AlternativePlan {
+                description: "aggressive".to_string(),
+                action_count: 5,
